const BATCH_NINE_DATE = "2026-06-13";
const BATCH_TEN_DATE = "2026-06-13";

const COMMON_SOURCES: readonly string[] = [
  "un-habitat",
  "ipcc-urban",
  "wikidata",
  "wikimedia-commons",
];

function placeSources(extra: readonly string[] = []): string[] {
  return Array.from(new Set([...COMMON_SOURCES, ...extra]));
}

interface PlaceSeed {
  slug: string;
  name: string;
  countrySlug: string;
  regionName?: string;
  category: NearbyWeekendPlace["category"];
  summary: string;
  connectedCitySlugs: string[];
  distanceBand?: NearbyWeekendPlace["distanceBand"];
  travelModeHint?: NearbyWeekendPlace["travelModeHint"];
  cautionNotes?: string;
  wikidataId?: string;
  officialUrl?: string;
  commonsCategory?: string;
  latitude?: number;
  longitude?: number;
  coordinateSource?: "wikidata";
  verificationStatus: NearbyWeekendPlace["verificationStatus"];
  verifiedAt?: string;
}

